import { page, renderHook } from "#test/browser"
import { useMediaQuery } from "."

describe("useMediaQuery", () => {
  test("returns true immediately when query matches on initial mount", async () => {
    await page.viewport(600, 800)

    const { result, unmount } = await renderHook(() =>
      useMediaQuery("(min-width: 500px)"),
    )

    expect(result.current).toBeTruthy()

    unmount()
  })

  test("returns the current match state and updates on viewport change", async () => {
    await page.viewport(400, 800)

    const { result, unmount } = await renderHook(() =>
      useMediaQuery("(min-width: 500px)"),
    )

    expect(result.current).toBeFalsy()

    await page.viewport(600, 800)

    await vi.waitFor(() => {
      expect(result.current).toBeTruthy()
    })

    unmount()
  })
})

"use client"

import { useCallback, useSyncExternalStore } from "react"
import { useEnvironment } from "@yamada-ui/react"

/**
 * `useMediaQuery` is a custom hook that detects whether it matches a media query.
 *
 * @see https://yamada-ui.com/docs/hooks/use-media-query
 */
export const useMediaQuery = (query: string, fallback = false): boolean => {
  const { getWindow } = useEnvironment()

  const subscribe = useCallback(
    (onStoreChange: () => void) => {
      const mql = getWindow()?.matchMedia(query)

      mql?.addEventListener("change", onStoreChange)

      return () => {
        mql?.removeEventListener("change", onStoreChange)
      }
    },
    [getWindow, query],
  )

  const getSnapshot = useCallback(() => {
    return getWindow()?.matchMedia(query).matches ?? fallback
  }, [getWindow, query, fallback])

  return useSyncExternalStore(subscribe, getSnapshot, getSnapshot)
}
